477	      ecb_mode_single_block_test(8'h17, AES_DECIPHER, nist_aes256_key, AES_256_BIT_KEY,
478	                                 nist_ecb_256_enc_expected3, nist_plaintext3);
479	    end
480	  endtask // aes_test
481	
482	
483	  //----------------------------------------------------------------
484	  // main
485	  //
486	  // The main test functionality.
487	  //----------------------------------------------------------------
488	  initial
489	    begin : main
490	      $display("   -= Testbench for AES started =-");
491	      $display("    ==============================");
492	      $display("");
493	
494	      init_sim();
495	      dump_dut_state();
496	      reset_dut();
497	      dump_dut_state();
498	
499	      aes_test();
500	
501	      display_test_results();
502	
503	      $display("");
504	      $display("*** AES simulation done. ***");
505	      $finish;
506	    end // main
507	endmodule // tb_aes
